mapper.select:
SELECT a.*, s.name AS student_name, s.student_no
FROM student_award a
LEFT JOIN student s ON a.student_id = s.pk_student


        AND a.student_id = #{studentId}


        AND a.award_level = #{awardLevel}


        AND a.award_name LIKE CONCAT('%', #{awardName}, '%')


        AND a.type = #{type}


ORDER BY a.award_date DESC

mapper.update:
UPDATE student_award
type = #{type}, award_name = #{awardName}, award_level = #{awardLevel}, award_date = #{awardDate}, issuing_authority = #{issuingAuthority}, description = #{description},
WHERE pk_award = #{pkAward}
